def validate_iec(iec, known_refs):
    problems = []

    # R4: Type check - iec must be a dict
    if not isinstance(iec, dict):
        return {"ok": False, "problems": ["iec must be a dict"]}

    # R1: Required fields check
    required_fields = ['selected_interpretation', 'strategy', 'basis_refs', 'residual', 'alternatives', 'revision_triggers']
    for field in required_fields:
        if field not in iec:
            problems.append(f"missing required field: {field}")

    if problems:
        return {"ok": False, "problems": problems}

    # R4: Type checks for fields
    if not isinstance(iec['selected_interpretation'], str):
        problems.append("selected_interpretation must be a string")
    if not isinstance(iec['strategy'], str):
        problems.append("strategy must be a string")
    if not isinstance(iec['basis_refs'], list):
        problems.append("basis_refs must be a list")
    else:
        for ref in iec['basis_refs']:
            if not isinstance(ref, str):
                problems.append(f"basis_refs must contain only strings, found {type(ref).__name__}")
                break
    if not isinstance(iec['residual'], list):
        problems.append("residual must be a list")
    if not isinstance(iec['alternatives'], list):
        problems.append("alternatives must be a list")
    if not isinstance(iec['revision_triggers'], list):
        problems.append("revision_triggers must be a list")

    if problems:
        return {"ok": False, "problems": problems}

    # R2: Strategy validation
    valid_strategies = {'DIRECT', 'CONTEXT_RESOLVE', 'CHOICE', 'BOUNDED_MULTI_VIEW', 'INTENT_PROBE', 'PREMISE_PROBE', 'DEFER'}
    if iec['strategy'] not in valid_strategies:
        problems.append(f"invalid strategy: {iec['strategy']}")

    # R3: Basis refs validation - all must be in known_refs
    # Convert known_refs to a set for efficient lookup if it's not already
    known_refs_set = set(known_refs)
    for ref in iec['basis_refs']:
        if ref not in known_refs_set:
            problems.append(f"fabrication detected: basis_ref '{ref}' not in known_refs")

    return {"ok": len(problems) == 0, "problems": problems}
